#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;signal.h&gt;
#include &lt;unistd.h&gt;

// We must use a volatile sig_atomic_t to guarantee safe, lock-free mutation 
// of this variable across asynchronous thread contexts.
volatile sig_atomic_t keep_running = 1;

// The actual Signal Handler function
void handle_sigint(int sig) {
    // The user pressed Ctrl+C. We do NOT call exit() here.
    // We simply flip the global state flag.
    keep_running = 0;
}

int main() {
    // 1. Prepare the sigaction struct
    struct sigaction sa;
    sa.sa_handler = handle_sigint;

    // 2. Block all other signals while our handler runs
    sigfillset(&sa.sa_mask);

    // 3. Restart interrupted system calls
    sa.sa_flags = SA_RESTART;

    // 4. Register the handler with the Kernel for SIGINT (Ctrl+C)
    if (sigaction(SIGINT, &sa, NULL) == -1) {
        perror("Failed to setup sigaction");
        exit(1);
    }

    printf("Server booting up. Press Ctrl+C to initiate safe shutdown.\n");

    // 5. The Main Event Loop
    while (keep_running) {
        // Server does its normal operations here...
        sleep(1); 
    }

    // 6. Graceful Teardown
    // Because we trapped SIGINT, the program didn't violently die.
    // We can now safely flush our database connections before exiting.
    printf("\nFlushing database logs to disk...\n");
    printf("Shutting down cleanly. Goodbye.\n");

    return 0;
}

